PART.SORT_ICON.jit = 'absolute [right:0.4rem] [top:50%] [transform:translateY(-50%)] inline-flex items-center [opacity:0.3]';
PART.TBODY_TD.jit = '[padding:var(--dt-cell-padding)] [vertical-align:middle] fg-[var(--dt-text-color)] bg-[var(--dt-bg)] [border-bottom:1px_solid_var(--dt-border-color)] [transition:background-color_0.12s_ease] {is-nowrap}:text-nowrap {is-ellipsis}:text-nowrap {is-ellipsis}:overflow-hidden {is-ellipsis}:[text-overflow:ellipsis] {is-ellipsis}:[max-width:0]';
PART.FILTER_ROW.jit = '[&_td]:bg-[var(--dt-bg)] [&_td]:[padding:4px_6px] [&_td]:[border-bottom:1px_solid_var(--dt-border-color)]';
PART.FILTER_CELL.jit = [
'relative [vertical-align:middle]',
'[&_.combobox-container]:h-[26px] [&_.combobox-container]:min-h-[26px] [&_.combobox-container]:text-[0.8rem] [&_.combobox-container]:[border:1px_solid_var(--dt-border-color)] [&_.combobox-container]:rounded-[4px] [&_.combobox-container]:[box-sizing:border-box]',
'[&_.combobox-label]:[min-height:unset] [&_.combobox-label]:[padding:0_6px] [&_.combobox-label]:[line-height:24px] [&_.combobox-label]:text-[0.8rem]',
'[&_.date-picker]:h-[26px] [&_.date-picker]:min-h-[26px] [&_.date-picker]:text-[0.8rem] [&_.date-picker]:[border:1px_solid_var(--dt-border-color)] [&_.date-picker]:rounded-[4px] [&_.date-picker]:[box-sizing:border-box] [&_.date-picker]:w-full [&_.date-picker]:flex',
'[&_.date-picker]:[--dp-control-py:0] [&_.date-picker]:[--dp-seg-padding-y:0_4px] [&_.date-picker]:[--dp-font-size:0.8rem] [&_.date-picker]:[--dp-line-height:24px]',
'[&_.date-picker-icon]:[padding:0_4px]',
'[&_.date-picker-seg]:[padding:0] [&_.date-picker-seg]:[line-height:24px]',
'[&_.date-picker-range-sep]:[padding:0_4px] [&_.date-picker-range-sep]:[line-height:24px]',
].join(' ');
PART.FILTER_INPUT.jit = 'block w-full [box-sizing:border-box] [height:26px] [padding:0_6px] [border:1px_solid_var(--dt-border-color)] rounded-[4px] bg-[var(--dt-bg)] fg-[var(--dt-text-color)] [font:inherit] text-[0.8rem] [line-height:26px] [outline:none] [transition:border-color_0.15s_ease] focus:[border-color:var(--dt-accent)] placeholder:fg-[var(--dt-text-muted)]';
PART.FILTER_RESET.jit = 'absolute [right:8px] [top:50%] [transform:translateY(-50%)] cursor-pointer text-[1rem] [line-height:1] fg-[var(--dt-text-muted)] [user-select:none] [z-index:1] hover:fg-[var(--dt-text-color)]';
PART.EMPTY_ROW.jit = '[&_td]:[text-align:center] [&_td]:fg-[var(--dt-text-muted)] [&_td]:[padding:2rem_1rem] [&_td]:[font-style:italic] [&_td]:{is-error}:fg-[var(--rui-danger,#d32f2f)]';
PART.FOOTER.jit   = 'flex items-center [justify-content:space-between] [padding:0.5rem_1rem] [border-top:1px_solid_var(--dt-border-color)] text-[0.8rem] fg-[var(--dt-text-muted)]';
PART.FOOTER_INFO.jit = 'text-nowrap';
PART.FOOTER_NAV.jit = 'flex gap-[2px] items-center';
PART.NAV_BUTTON.jit = '[appearance:none] [border:1px_solid_var(--dt-border-color)] bg-[var(--dt-bg)] fg-[var(--dt-text-color)] [padding:0.25rem_0.55rem] [min-width:1.75rem] rounded-[4px] text-[0.75rem] cursor-pointer [line-height:1] [text-align:center] [transition:background-color_0.12s_ease] hover:not-disabled:bg-[var(--dt-bg-hover)] disabled:[opacity:0.35] disabled:cursor-default {is-active}:bg-[var(--dt-accent)] {is-active}:fg-[var(--dt-on-accent)] {is-active}:[border-color:var(--dt-accent)] {is-active}:fw-600';
PART.SENTINEL.jit = [
'flex items-center justify-center [min-height:48px] [padding:1rem] text-[0.8rem] fg-[var(--dt-text-muted)] [transition:opacity_0.2s_ease]',
'{is-done}:[font-style:italic] {is-done}:[opacity:0.6]',
'{is-error}:fg-[var(--rui-danger,#d32f2f)] {is-error}:cursor-pointer {is-error}:hover:[text-decoration:underline]',
'{is-loading}:after:inline-block {is-loading}:after:w-[18px] {is-loading}:after:h-[18px] {is-loading}:after:[border:2px_solid_var(--dt-border-color)] {is-loading}:after:[border-top-color:var(--dt-accent)] {is-loading}:after:rounded-[50%] {is-loading}:after:[animation:rui-spin_0.6s_linear_infinite] {is-loading}:after:[margin-left:0.5rem] {is-loading}:after:[vertical-align:middle]',
].join(' ');