/**
 * @fileoverview DataTable component definition for JIT pipeline.
 *
 * @module module/DataTable.def
 */

import razyui from '../index.js';import { PART } from './DataTable/constants.js';
/**
 * The definition object for the DataTable component.
 *
 * @type {Object}
 */
export const DataTableDef = {
    name: 'DataTable',
    tag: 'rui-data-table',

    tokens: {
        prefix: 'dt',
        tokens: {
            'radius':             { ref: 'radius.md',           description: 'Container border radius' },
            'bg':                 { ref: 'color.bg',            description: 'Background' },
            'bg-hover':           { ref: 'color.bg-hover',      description: 'Hover background' },
            'bg-stripe':          { ref: 'color.bg-inset',      description: 'Stripe background' },
            'bg-header':          { ref: 'color.bg-raised',     description: 'Header background' },
            'border-color':       { ref: 'color.border',        description: 'Border color' },
            'text-color':         { ref: 'color.text',          description: 'Text color' },
            'text-muted':         { ref: 'color.text-muted',    description: 'Muted text' },
            'accent':             { ref: 'color.accent',        description: 'Accent color' },
            'on-accent':          { ref: 'color.on-accent',     description: 'Text on accent' },
            'font-size':          { value: '0.85rem',           description: 'Cell font size' },
            'header-font-size':   { value: '0.8rem',            description: 'Header font size' },
            'header-font-weight': { value: '600',               description: 'Header font weight' },
            'cell-padding':       { value: '0.4rem 0.8rem',       description: 'Cell padding' },
            'cell-padding-compact': { value: '0.3rem 0.6rem', description: 'Compact cell padding' },
        },
    },

    states: {
        initial: 'idle',
        states: {
            idle:      { on: { LOAD: 'loading' } },
            loading:   { on: { LOADED: 'idle', ERROR: 'idle' } },
        },
        effects: {
            loading(ctx) {
                if (ctx.el) razyui(ctx.el).addClass('is-loading');
            },
            'loading:exit'(ctx) {
                if (ctx.el) razyui(ctx.el).removeClass('is-loading');
            },
        },
    },

    template: {
        slots: {
            root:   { element: 'div',   classes: ['data-table-container'] },
            table:  { element: 'table', classes: ['data-table'] },
            thead:  { element: 'thead', classes: [] },
            tbody:  { element: 'tbody', classes: [] },
            footer: { element: 'div',   classes: ['data-table-footer'] },
        },
    },

    jitParts: {
        [PART.CONTAINER]: PART.CONTAINER,
        [PART.WRAPPER]: PART.WRAPPER,
        [PART.TABLE]: PART.TABLE,
        [PART.THEAD]: PART.THEAD,
        [PART.THEAD_TH]: PART.THEAD_TH,
        [PART.SORT_ICON]: PART.SORT_ICON,
        [PART.TBODY_TD]: PART.TBODY_TD,
        [PART.FILTER_ROW]: PART.FILTER_ROW,
        [PART.FILTER_CELL]: PART.FILTER_CELL,
        [PART.FILTER_INPUT]: PART.FILTER_INPUT,
        [PART.FILTER_RESET]: PART.FILTER_RESET,
        [PART.EMPTY_ROW]: PART.EMPTY_ROW,
        [PART.FOOTER]: PART.FOOTER,
        [PART.FOOTER_INFO]: PART.FOOTER_INFO,
        [PART.FOOTER_NAV]: PART.FOOTER_NAV,
        [PART.NAV_BUTTON]: PART.NAV_BUTTON,
        [PART.SENTINEL]: PART.SENTINEL,
    },

    styles: {},  /* All styles expressed via JIT; keyframes use shared razyui.motion */

    observedAttrs: ['data', 'columns', 'page-size', 'sortable'],

    attrMap: {
        data:       'data',
        columns:    'columns',
        'page-size': 'pageSize',
        sortable:   'sortable',
    },
};

export default DataTableDef;
